uint32_t maxf = 0;

for (int i = 0; i < 256; i++) if (histo[i] > maxf) maxf = histo[i];

uint16_t histo16[256] = { 0 };

for (int i = 0; i < 256; i++) {

if (!histo[i]) continue;

uint32_t v = maxf > 60000 ? (uint32_t)((uint64_t)histo[i] * 60000 / maxf) : histo[i];

histo16[i] = v ? (uint16_t)v : 1;

}

struct table t;

tdefl_optimize_huffman_table(&t, 256, MAX_BITS, histo16);

uint16_t decode_table[TABLE_ENTRIES] = { 0 };

for (int i = 0; i < 256; i++) {

if (t.m_huff_code_sizes[i]) {

if (t.m_huff_code_sizes[i] > MAX_BITS) {

fprintf(stderr, "code length %d exceeds MAX_BITS %d\n",

t.m_huff_code_sizes[i], MAX_BITS);

return 1;

}

for (int e = 0; e < (1 << (MAX_BITS - t.m_huff_code_sizes[i])); e++) {

decode_table[t.m_huff_codes[i] | (e << t.m_huff_code_sizes[i])] = (i << 8) | t.m_huff_code_sizes[i];

}

}

}

